prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?orgName WHERE {
  ?model a bboExt:Model .
  FILTER(STR(?model) = "https://www.teamingai-project.eu/model/0ba102e82f484407a4dbcb9bcafdd920" ||
         STR(?model) = "0ba102e82f484407a4dbcb9bcafdd920")
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:belongsTo ?org . ?org bbo:name ?orgName . }
}
LIMIT 25

